#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int C, D, L;
        scanf("%d %d %d", &C, &D, &L);
        int min_legs = D * 4;
        int max_legs = D * 4 + C * 4;
        if (L >= min_legs && L <= max_legs && (L - D * 4) % 4 == 0 && (L - D * 4) / 4 <= 2 * D) {
            printf("yes\n");
        } else {
            printf("no\n");
        }
    }
    return 0;
}

